"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[864510],{207167:e=>{e.exports=JSON.parse('{"tag":{"label":"input","permalink":"/dst-api-webdocs/docs/tags/input","allTagsPath":"/dst-api-webdocs/docs/tags","count":28,"items":[{"id":"game-scripts/widgets/button","title":"Button","description":"Base class for interactive UI buttons, handling input, focus, state management, and visual feedback.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/button"},{"id":"game-scripts/widgets/canceltipwidget","title":"Canceltipwidget","description":"Displays a localized UI tip indicating how to press and hold the cancel button to disconnect from a session.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/canceltipwidget"},{"id":"game-scripts/widgets/redux/chatsidebar","title":"Chatsidebar","description":"Manages the UI layout and input handling for the lobby chat sidebar, including the chat message input box, chat message history display, and player list panel.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/chatsidebar"},{"id":"game-scripts/widgets/consolehistorywidget","title":"Consolehistorywidget","description":"Renders a scrollable history of past console commands for user selection and completion.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/consolehistorywidget"},{"id":"game-scripts/widgets/controls","title":"Controls","description":"Manages the player HUD, input feedback, map UI, crafting menu, and wheel-based controls for all player interactions in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/controls"},{"id":"game-scripts/widgets/redux/craftingmenu_pinbar","title":"Craftingmenu Pinbar","description":"Manages the pinned recipe display and navigation UI for the crafting menu HUD, including page switching, focus handling, and prototype status indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/craftingmenu_pinbar"},{"id":"game-scripts/widgets/redux/craftingmenu_pinslot","title":"Craftingmenu Pinslot","description":"Manages a pinned recipe slot in the crafting menu, handling recipe assignment, UI rendering, input, and interaction with recipe details and crafting logic.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/craftingmenu_pinslot"},{"id":"game-scripts/widgets/imagebutton","title":"ImageButton","description":"A UI widget that displays an image and responds to user interaction states such as focus, press, disable, and selection, with support for per-state texture and color customization.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/imagebutton"},{"id":"game-scripts/widgets/redux/lobbychatqueue","title":"Lobbychatqueue","description":"Manages the display and scrolling of lobby chat history in the Redux UI, handling message insertion, pagination, and input focus redirection.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/lobbychatqueue"},{"id":"game-scripts/components/maxwelltalker","title":"Maxwelltalker","description":"Manages scripted dialogue and cutscenes for Maxwell, handling speech synchronization, input skipping, player control disable/enable, and camera control during narrative events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maxwelltalker"},{"id":"game-scripts/widgets/menu","title":"Menu","description":"Manages a dynamic collection of interactive menu items with keyboard and controller focus navigation, layout, and styling support.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/menu"},{"id":"game-scripts/widgets/mousetracker","title":"Mousetracker","description":"Tracks mouse movement relative to a joystick widget and triggers direction-specific animations for UI interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/mousetracker"},{"id":"game-scripts/widgets/numericspinner","title":"Numericspinner","description":"A UI widget for selecting integer values within a specified range, supporting both spinner buttons and direct text input.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/numericspinner"},{"id":"game-scripts/components/playeractionpicker","title":"Playeractionpicker","description":"Determines valid player actions based on context (mouse position, target, held item, and modifiers).","permalink":"/dst-api-webdocs/docs/game-scripts/components/playeractionpicker"},{"id":"game-scripts/components/playercontroller","title":"Playercontroller","description":"Manages player input, locomotion prediction, targeting, placement, and combat actions for the player entity in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playercontroller"},{"id":"game-scripts/widgets/radiobuttons","title":"Radiobuttons","description":"Manages a group of radio button widgets for UI selection controls, supporting horizontal/vertical layouts and data-based selection.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/radiobuttons"},{"id":"game-scripts/widgets/resurrectbutton","title":"Resurrectbutton","description":"Provides a UI button and input handling for triggering character resurrection via an effigy or grave.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/resurrectbutton"},{"id":"game-scripts/components/reticule","title":"Reticule","description":"Manages the visual targeting reticule for controller-based items, handling position updates, validity checks, and twin-stick aiming modes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/reticule"},{"id":"game-scripts/widgets/spinner","title":"Spinner","description":"A UI widget that displays and allows selection from a list of options using arrow buttons, supporting both keyboard/controller input and programmatic control.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/spinner"},{"id":"game-scripts/components/strafer","title":"Strafer","description":"Manages strafing input and facing direction for player entities during movement, integrating with locomotion and player controller systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/strafer"},{"id":"game-scripts/util/textcompleter","title":"Textcompleter","description":"Manages text completion and suggestion behavior for console-style input, supporting both Lua code autocompletion and word-suggestion modes.","permalink":"/dst-api-webdocs/docs/game-scripts/util/textcompleter"},{"id":"game-scripts/widgets/textedit","title":"Textedit","description":"A UI widget for displaying and editing text input with keyboard/controller support, formatting, and word prediction.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/textedit"},{"id":"game-scripts/widgets/textedit_steamdeck","title":"Textedit Steamdeck","description":"A UI widget for text input that supports virtual keyboard editing, word prediction, text formatting, and keyboard/controller control handling.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/textedit_steamdeck"},{"id":"game-scripts/widgets/texteditlinked","title":"Texteditlinked","description":"A text input widget that links to adjacent text boxes to enable multi-box text entry flow, such as for password or code entry fields.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/texteditlinked"},{"id":"game-scripts/widgets/wheel","title":"Wheel","description":"Manages a circular UI menu for selecting actions or items, supporting both keyboard/mouse and gamepad navigation.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/wheel"},{"id":"game-scripts/widgets/wordpredictionwidget","title":"Wordpredictionwidget","description":"Renders a UI widget for word prediction in the console, supporting keyboard and mouse navigation through prediction suggestions.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/wordpredictionwidget"},{"id":"game-scripts/util/wordpredictor","title":"Wordpredictor","description":"Manages word prediction for text input by scanning dictionaries and returning matching completions based on user-typed prefixes.","permalink":"/dst-api-webdocs/docs/game-scripts/util/wordpredictor"},{"id":"game-scripts/widgets/writeablewidget","title":"Writeablewidget","description":"Manages the in-game text input interface for writing to writeable objects (e.g., signs, notebooks), handling UI rendering, input processing, and communication with the networked writeable component.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/writeablewidget"}],"unlisted":false}}')}}]);